-- One-time bulk import of Lulu's expenses, cash withdrawals, and bank
-- deposits from the owner-provided sheets (LULU__Expenses_1.pdf,
-- LULU__Cash_Flow.pdf, LULU__Bank_Account.pdf), covering Oct 2025 - Jul 2026.
-- Run this once in the Supabase SQL editor.
--
-- Row counts: 645 expenses, 20 cash transactions, 23 incomes
-- Verified against the sheets' own totals before generating this file:
--   cash balance  = -EUR 17.12   (matches)
--   bank balance  =  EUR 27,550.39 (matches)
--
-- NOTE: one bank deposit of EUR 2,000.00 had no date on the source sheet
-- and was left out - ask her for the date if it should be added.
do $$
declare
  v_boat_id uuid;
begin
  select id into v_boat_id from public.boats where lower(name) in ('לולו', 'lulu') limit 1;
  if v_boat_id is null then
    raise exception 'Boat not found by name (tried ''לולו'' / ''LULU'') - check the boat name in the boats table';
  end if;




end $$;
